#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c<=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
#define Clear(a) memset(a,0,sizeof(a))
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();int flag=1;
	while(ch<'0'||ch>'9')flag-=(ch=='-')<<1,ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return res * flag ;
}
const int N=1e6+5,M=2e6+5,INF=4e18;
struct Graph{int head[N],des[M],nxt[M],val[M],cnt;//
	inline void ins(int x,int y,int z){des[++cnt]=y;val[cnt]=z;nxt[cnt]=head[x];head[x]=cnt;}}a;
int cir[M],val[M],dep[M],deq[M],H,T,ans,p,mx,g[N],dp[N],Mx=INF,To[N];bool isc[N],vis[N];
struct Sort{int val,num;inline bool operator < (const Sort &x)const{return val<x.val;}};
inline Sort Node(int x,int y){Sort kkk;kkk.val=x;kkk.num=y;return kkk;}priority_queue<Sort>q0,q1;
inline long long Cnt(int k){return deq[k]-val[k-1];}
int dfs0(int u,int fa)
{
	int res;vis[res=u]=1;bool flag=0;grep(a,u,i)
	{
		int v=a.des[i];if(i==fa)continue;
		if(vis[v]){if(!flag)flag=1,isc[res=cir[++p]=v]=1,val[p]=a.val[i];continue;}
		int tmp=dfs0(v,i^1);if(tmp!=v){isc[cir[++p]=v]=1;val[p]=a.val[i];flag=1;res=tmp;}
	}return res;
}
void dfs1(int u,int fa)
{
//	printf("%d\n",u);
    grep(a,u,i)
    {
        int v=a.des[i];if(i==fa||isc[v])continue;dfs1(v,i^1);
        if(dp[u]<dp[v]+a.val[i])g[u]=dp[u],dp[u]=dp[v]+a.val[i];
        else if(g[u]<dp[v]+a.val[i])g[u]=dp[v]+a.val[i];
        mx=max(mx,dp[u]+g[u]);
    }
}
int dfs2(int u,int fa)
{
	int res=0;grep(a,u,i)
	{
		int v=a.des[i];if(isc[v]||i==fa)continue;
		res=max(res,dfs2(v,i^1)+a.val[i]);
	}return res;
}
signed main()
{
//	freopen("aa.txt","r",stdin);
	a.cnt=1;int n=read();rep(1,n,i){int x=read(),y=read(),z=read();a.ins(x,y,z);a.ins(y,x,z);}
//	rep(1,n,i)grep(a,i,j)printf("%d' %d'\n",i,a.des[j]);
	rep(1,n,Q)if(!vis[Q])
	{
//		printf("case %d : \n",Q);
		mx=p=0;dfs0(Q,0);rep(1,p,i)dfs1(cir[i],0);
		rep(1,p,i)dep[i]=dfs2(cir[i],0);
		rep(1,p-1,i)val[i+p]=val[i],cir[i+p]=cir[i],dep[i+p]=dep[i];val[2*p-1]=0;
		rep(2,2*p-2,i)val[i]+=val[i-1];
//		rep(1,2*p-1,i)printf("%d ",val[i]);puts("");
//		rep(1,2*p-1,i)printf("%d ",cir[i]);puts("");
//		rep(1,2*p-1,i)printf("%d ",dep[i]);puts("");
//		rep(1,2*p-1,i)printf("%d ",dep[i]-val[i-1]);puts("");
//		rep(1,2*p-1,i)printf("%d ",dep[i]+val[i-1]);puts("");
//		q0.push(Node(0,0));q1.push(Node(0,0));
		q0.push(Node(dep[1],1));q1.push(Node(dep[1],1));rep(2,2*p-1,i)
		{
			
			while(q0.top().num<=i-p)q0.pop();while(q1.top().num<=i-p)q1.pop();
			q0.push(Node(dep[i]+val[i-1],i));q1.push(Node(dep[i]-val[i-1],i));
			Sort tmp0=q0.top(),tmp1=q1.top();q0.pop();q1.pop();
			if(i>=p)
			{
				if(tmp0.num==tmp1.num)
				{
					while(q0.top().num<=i-p)q0.pop();while(q1.top().num<=i-p)q1.pop();
					Mx=min(Mx,max(tmp0.val+q1.top().val,tmp1.val+q0.top().val));
				}
				else Mx=min(Mx,tmp0.val+tmp1.val);
			}
//			printf("%d %d //%d %d// %d %d\n",i,Mx,tmp0.val,tmp1.val,q0.top().val,q1.top().val);
			q0.push(tmp0);q1.push(tmp1);
		}
	}
	printf("%lld",max(Mx,mx));
}
